144	type preClaimHookCallResult struct {
145		err error
146	}
147	
148	func callPreClaimHookWithTimeout(ctx context.Context, hook PreClaimHook, timeout time.Duration) (error, bool) {
149		if hook == nil {
150			return nil, false
151		}
152		if timeout <= 0 {
153			timeout = DefaultPreClaimTimeout
154		}
155		hookCtx, cancel := context.WithTimeout(ctx, timeout)
156		defer cancel()
157	
158		resultCh := make(chan preClaimHookCallResult, 1)
159		go func() {
160			resultCh <- preClaimHookCallResult{err: hook(hookCtx)}
161		}()
162	
163		select {
164		case result := <-resultCh:
165			if errors.Is(hookCtx.Err(), context.DeadlineExceeded) || errors.Is(result.err, context.DeadlineExceeded) {
166				return context.DeadlineExceeded, true
167			}
168			return result.err, false
169		case <-hookCtx.Done():
170			if errors.Is(hookCtx.Err(), context.DeadlineExceeded) {
171				return context.DeadlineExceeded, true
172			}
173			return hookCtx.Err(), false
174		}
175	}
