13			Use:   "clear-cooldowns",
14			Short: "Bulk-clear queue-drain cooldowns",
15			Long: `clear-cooldowns scans beads with an active queue-drain cooldown and clears
16	them in one pass. Use after a systemic issue (e.g., a push-layer failure) is
17	resolved so blocked beads re-enter the execution queue without per-bead --unset loops.
18	
19	Requires --all or --status to prevent accidental bulk clears.`,
20			Example: `  # Clear all active cooldowns
21	  ddx work clear-cooldowns --all
22	
23	  # Clear only push_failed cooldowns
24	  ddx work clear-cooldowns --status push_failed
25	
26	  # Preview without modifying state
27	  ddx work clear-cooldowns --all --dry-run`,
28			Args: cobra.NoArgs,
29			RunE: f.runWorkClearCooldowns,
30		}
31		cmd.Flags().Bool("all", false, "Clear cooldowns on every bead with retry-after set")
32		cmd.Flags().String("status", "", "Clear only beads where last-status matches this value")
33		cmd.Flags().Bool("dry-run", false, "Print what would be cleared without modifying state")
34		return cmd
35	}
